import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { MedicalRecord } from '../../core/data.models';
import { MedicalService } from '../../services/medical.service';

@Component({
  selector: 'app-medical-detail',
  templateUrl: './medical-detail.component.html'
})
export class MedicalDetailComponent implements OnInit {
  item?: MedicalRecord;

  constructor(private route: ActivatedRoute, private router: Router, private svc: MedicalService) {}

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (!id) return;
    this.svc.list$.subscribe(list => {
      this.item = list.find(i => i.id === id);
      if (!this.item) this.router.navigate(['/medical']);
    });
  }
}
<div *ngIf="item" class="card">
  <h2>{{item.person}}</h2>
  <div class="small">Type: {{item.type}}</div>
  <div style="margin-top:8px">Date: {{item.date || '—'}}</div>
  <div style="margin-top:8px">Provider: {{item.provider || '—'}}</div>
  <div style="margin-top:8px">Notes: {{item.notes || '—'}}</div>
  <div style="margin-top:12px">
    <a [routerLink]="[item.id, 'edit']">Edit</a>
    <a routerLink="/medical" style="margin-left:8px">Back</a>
  </div>
</div>
